/**
 * @fileoverview Generate the consumer-facing TypeScript stubs that @cldmv/slothlet ships in place of
 * its own declarations. The real declarations live in the standalone @cldmv/slothlet-types package.
 * @module @cldmv/slothlet/tools/build-typestubs
 * @internal
 * @description
 * @cldmv/slothlet no longer publishes its own `.d.mts` declarations. Instead, for the production
 * (`default`) resolution condition every typed export resolves to a tiny stub under `types/stub/`
 * that re-exports the matching subpath from `@cldmv/slothlet-types`. The rich in-repo declarations
 * (`types/src/**`) stay reachable through the `slothlet-dev` condition for this repo's own checks.
 *
 * One stub is emitted per real declaration file so the export-map wildcards (`./helpers/*`, …)
 * resolve 1:1. Stubs carry no source maps. An export whose declaration is NOT carried by the
 * satellite (it has no `types/dist/**` mirror, e.g. the empty `./devcheck`) is shipped as a
 * self-contained copy of its real declaration instead of a re-export.
 *
 * Resolution for a consumer:
 *   `@cldmv/slothlet/helpers/config`
 *     → core export `./helpers/*` (default) → `types/stub/lib/helpers/config.d.mts`
 *     → `export * from "@cldmv/slothlet-types/helpers/config"`
 *     → satellite export `./helpers/*` → its `lib/helpers/config.d.mts`.
 *
 * If `@cldmv/slothlet-types` is not installed, that re-export fails to resolve and TypeScript reports
 * `Cannot find module '@cldmv/slothlet-types'` — the signal that the optional types peer is missing.
 *
 * @example
 * // after build:types (so types/src + types/dist exist):
 * node tools/build/build-typestubs.mjs
 */

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const projectRoot = path.dirname(path.dirname(__dirname));

const SATELLITE = "@cldmv/slothlet-types";
const typesDir = path.join(projectRoot, "types");
const srcTypesDir = path.join(typesDir, "src");
const distTypesDir = path.join(typesDir, "dist");
const stubDir = path.join(typesDir, "stub");

/** Export keys that carry no TypeScript types (JSON, schemas, runtime-only locale files). @internal */
const SKIP_KEYS = new Set(["./package.json"]);

/* ---------- helpers ---------- */

function ensureDir(dir) {
	fs.mkdirSync(dir, { recursive: true });
}

function writeStub(absFile, body) {
	ensureDir(path.dirname(absFile));
	const header =
		`// AUTO-GENERATED by tools/build/build-typestubs.mjs — do not edit.\n` +
		`// Re-exports the real declarations from ${SATELLITE} (install it for TypeScript support).\n`;
	fs.writeFileSync(absFile, header + body.replace(/\n*$/, "") + "\n");
}

/**
 * Whether a declaration file exposes a default export (so the stub must re-export it too — a bare
 * `export *` never forwards the default).
 * @internal
 * @param {string} absFile - Path to a `.d.mts` declaration.
 * @returns {boolean}
 */
function hasDefaultExport(absFile) {
	let txt;
	try {
		txt = fs.readFileSync(absFile, "utf8");
	} catch {
		return false;
	}
	return /^\s*export\s+default\s/m.test(txt) || /\bas\s+default\s*\}/.test(txt) || /export\s*\{\s*default\b/.test(txt);
}

/** Strip a trailing `//# sourceMappingURL=…` comment (stubs ship no maps). @internal */
function stripSourceMap(txt) {
	return txt.replace(/\r?\n?\/\/#\s*sourceMappingURL=[^\r\n]*\s*$/, "");
}

/**
 * The `slothlet-dev` (src) types path for an export, or its flat `types` string, as `./types/…`.
 * @internal
 * @returns {string|null}
 */
function devTypesPath(value) {
	if (value && typeof value === "object") {
		const dev = value["slothlet-dev"];
		if (dev && typeof dev === "object" && typeof dev.types === "string") return dev.types;
		if (typeof value.types === "string") return value.types;
	}
	return null;
}

/** `./types/src/lib/helpers/*.d.mts` | `./types/index.d.mts` → `lib/helpers/*.d.mts` | `index.d.mts`. @internal */
function typesRelative(typesPath) {
	return typesPath.replace(/^\.\/types\/(?:src\/)?/, "");
}

/** `helpers/config` → re-export body (named always; default only when the target has one). @internal */
function reexportBody(subpath, withDefault) {
	const spec = subpath ? `${SATELLITE}/${subpath}` : SATELLITE;
	let body = `export * from "${spec}";`;
	if (withDefault) body += `\nexport { default } from "${spec}";`;
	return body;
}

/* ---------- main ---------- */

function main() {
	if (!fs.existsSync(srcTypesDir)) {
		throw new Error(`missing ${path.relative(projectRoot, srcTypesDir)} — run "npm run build:types" first`);
	}
	const pkg = JSON.parse(fs.readFileSync(path.join(projectRoot, "package.json"), "utf8"));
	const exportsMap = pkg.exports || {};

	fs.rmSync(stubDir, { recursive: true, force: true });
	ensureDir(stubDir);

	let count = 0;
	const warnings = [];

	for (const [key, value] of Object.entries(exportsMap)) {
		if (SKIP_KEYS.has(key)) continue;
		// runtime-only locale + schema passthroughs carry no .d.mts
		if (key.startsWith("./i18n/language") || key.startsWith("./schemas")) continue;

		// Root: always re-export the satellite root (which aggregates the default-bearing entry).
		if (key === ".") {
			writeStub(path.join(stubDir, "index.d.mts"), reexportBody("", true));
			count++;
			continue;
		}

		const devPath = devTypesPath(value);
		if (!devPath) continue; // not a typed export

		const rel = typesRelative(devPath); // e.g. lib/helpers/*.d.mts | devcheck.d.mts
		const subpath = key.replace(/^\.\//, ""); // e.g. helpers/* | runtime/async | errors

		if (rel.includes("*")) {
			// Wildcard export: emit one stub per real declaration so `./helpers/*` resolves 1:1.
			// Enumerate from types/dist — the exact tree the satellite carves and ships — so a stub is
			// never emitted for a satellite subpath that won't exist (src/dist skew would do that).
			const dirRel = path.posix.dirname(rel); // lib/helpers
			const distDir = path.join(distTypesDir, dirRel);
			const base = subpath.replace(/\/\*$/, ""); // helpers
			let names;
			try {
				names = fs
					.readdirSync(distDir)
					.filter((n) => n.endsWith(".d.mts"))
					.map((n) => n.replace(/\.d\.mts$/, ""));
			} catch {
				warnings.push(`no dist dir for wildcard export ${key} (${dirRel}) — run "npm run build:types" first`);
				continue;
			}
			for (const name of names) {
				const distFile = path.join(distDir, `${name}.d.mts`);
				writeStub(path.join(stubDir, dirRel, `${name}.d.mts`), reexportBody(`${base}/${name}`, hasDefaultExport(distFile)));
				count++;
			}
			continue;
		}

		// Exact export. If the satellite carries it (a types/dist mirror exists), re-export; otherwise
		// ship the real (self-contained) declaration as the stub — e.g. the empty `./devcheck`.
		const distFile = path.join(distTypesDir, rel);
		const stubFile = path.join(stubDir, rel);
		if (fs.existsSync(distFile)) {
			writeStub(stubFile, reexportBody(subpath, hasDefaultExport(distFile)));
		} else {
			const srcFile = path.join(srcTypesDir, rel);
			const rootFile = path.join(typesDir, rel); // root-level decls (devcheck.d.mts) live at types/<rel>
			const realFile = fs.existsSync(srcFile) ? srcFile : fs.existsSync(rootFile) ? rootFile : null;
			if (!realFile) {
				warnings.push(`no declaration found for ${key} (${rel}) — skipped`);
				continue;
			}
			const txt = stripSourceMap(fs.readFileSync(realFile, "utf8"));
			if (/from\s+["']\.\.?\//.test(txt) || /import\(["']\.\.?\//.test(txt)) {
				warnings.push(`self-contained stub for ${key} has relative refs that will not ship — review ${rel}`);
			}
			writeStub(stubFile, txt);
		}
		count++;
	}

	for (const w of warnings) console.warn(`• ${w}`);
	console.log(`✓ build:typestubs — wrote ${count} stubs to ${path.relative(projectRoot, stubDir)}`);
}

try {
	main();
} catch (err) {
	console.error(`build-typestubs failed: ${err.message}`);
	process.exitCode = 1;
}
